package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import net.minecraft.util.IChatComponent;
import java.io.IOException;

public class S45PacketTitle implements Packet<INetHandlerPlayClient> {
    public enum Type { TITLE, SUBTITLE, TIMES, CLEAR, RESET }
    private Type type;
    private IChatComponent message;
    private int fadeInTime, stayTime, fadeOutTime;

    public S45PacketTitle() {}
    public S45PacketTitle(Type typeIn, IChatComponent messageIn) {
        this.type = typeIn;
        this.message = messageIn;
    }
    public S45PacketTitle(int fadeInIn, int stayIn, int fadeOutIn) {
        this.type = Type.TIMES;
        this.fadeInTime = fadeInIn;
        this.stayTime = stayIn;
        this.fadeOutTime = fadeOutIn;
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleTitle(this); }
    public Type getAction() { return this.type; }
    public IChatComponent getMessage() { return this.message; }
    public int getFadeInTime() { return this.fadeInTime; }
    public int getStayTime() { return this.stayTime; }
    public int getFadeOutTime() { return this.fadeOutTime; }
}

